            new StylePreset { Id = 340, Name = "Cyberpunk Edgerunner", Description = "Neon cyberpunk anime mercenary style", PromptTemplate = "Transform the subject into a cyberpunk anime edgerunner mercenary. CRITICAL: Preserve the subject's exact facial features and identity. Render in vivid anime style — sharp dynamic lines, intense expressions, and exaggerated action poses. Cybernetic augmentations visible — glowing circuit lines under the skin, a chrome cyberarm, optical implants with HUD display in the eyes. Wearing a punk-tech jacket with neon LED trim, tactical vest, and combat boots. Dual-wielding futuristic pistols. Background of a rain-soaked Night City at night — towering megabuildings with holographic advertisements, neon signs in pink and cyan, flying cars. Neon pink, cyan, chrome, and deep purple color palette. Cyberpunk anime art quality.", Category = "Anime & Gaming", IconEmoji = "\U0001F306", AccentColor = "#E040FB", IsActive = true, SortOrder = 100 },
            new StylePreset { Id = 341, Name = "Pirate King Style", Description = "Grand Line pirate captain adventure anime", PromptTemplate = "Transform the subject into a Grand Line pirate captain in One Piece anime style. CRITICAL: Preserve the subject's exact facial features and identity. Render in Eiichiro Oda's distinctive manga style — bold expressive features, dynamic exaggerated proportions, and infectious grin of adventure. Wearing a straw hat with a red band, an open red vest revealing a muscular chest, blue shorts, and sandals. A pirate flag with skull and crossbones flying in the background. Confident captain pose on the bow of a pirate ship — one foot on the railing, fist raised to the sky. Background of the vast Grand Line ocean — massive waves, a pirate ship, distant mysterious islands. Vibrant saturated color palette — warm reds, blues, and ocean teal. One Piece manga/anime art quality.", Category = "Anime & Gaming", IconEmoji = "\U0001F3F4\u200D\u2620\uFE0F", AccentColor = "#D32F2F", IsActive = true, SortOrder = 101 },
            new StylePreset { Id = 342, Name = "Saiyan Warrior Style", Description = "Super powered energy warrior anime", PromptTemplate = "Transform the subject into a powerful Saiyan warrior in Dragon Ball Z anime style. CRITICAL: Preserve the subject's exact facial features and identity. Render in Akira Toriyama's iconic style — bold clean lines, sharp angular features, and intense determined expression. Hair transformed into Super Saiyan form — spiky golden blonde hair standing straight up, radiating golden ki energy aura. Eyes turned fierce teal green. Wearing Saiyan battle armor — blue bodysuit with white and gold chest plate, white gloves and boots. Powering up in a battle stance — fists clenched, ki energy crackling, ground cracking beneath. Background of a barren rocky battlefield — craters, shattered mountains, dramatic sky with energy beams. Intense gold, blue, and white color palette. Dragon Ball Z anime art quality.", Category = "Anime & Gaming", IconEmoji = "\U0001F525", AccentColor = "#FFD600", IsActive = true, SortOrder = 102 },
            new StylePreset { Id = 343, Name = "Demon Slayer Hashira", Description = "Breathing technique samurai swordsman", PromptTemplate = "Transform the subject into a Hashira-rank demon slayer swordsman. CRITICAL: Preserve the subject's exact facial features and identity. Render in Ufotable's stunning anime style — crisp detailed linework with vivid coloring and dramatic shading. Wearing the Demon Slayer Corps uniform — black gakuran jacket with a white belt, and a distinctive haori with unique geometric or floral design. Gripping a blade that changes color with breathing technique — the blade edge glowing with elemental energy. Performing a Breathing Form technique — dynamic slash pose with swirling elemental effects (water dragons, flame trails, or lightning arcs). Background of a moonlit bamboo forest with wisteria flowers. Rich saturated color palette with glowing technique effects. Ufotable-quality cinematic anime art.", Category = "Anime & Gaming", IconEmoji = "\u2694\uFE0F", AccentColor = "#7B1FA2", IsActive = true, SortOrder = 103 },
            new StylePreset { Id = 344, Name = "Jujutsu Sorcerer Style", Description = "Cursed energy dark fantasy sorcerer", PromptTemplate = "Transform the subject into a powerful jujutsu sorcerer. CRITICAL: Preserve the subject's exact facial features and identity. Render in MAPPA's Jujutsu Kaisen anime style — edgy dynamic character design with sharp features and intense eyes. Wearing the Tokyo Jujutsu High uniform — navy blue high-collar jacket and pants. Channeling cursed energy — dark purple and black swirling aura emanating from the body, geometric cursed technique patterns forming in the air. One hand extended performing a Domain Expansion hand seal. Background of a dark supernatural battlefield — cursed spirits as shadowy forms, shattered terrain, an eerie barrier forming as an inky void with floating cursed symbols. Dark moody color palette — midnight blue, purple, black, with electric blue highlights. Dark supernatural anime art quality.", Category = "Anime & Gaming", IconEmoji = "\U0001F441\uFE0F", AccentColor = "#311B92", IsActive = true, SortOrder = 104 },
            new StylePreset { Id = 345, Name = "Titan Scout Style", Description = "Elite Scout Regiment soldier dark anime", PromptTemplate = "Transform the subject into an elite Scout Regiment soldier from Attack on Titan. CRITICAL: Preserve the subject's exact facial features and identity. Render in semi-realistic anime style with intense dramatic expressions. Wearing the Survey Corps uniform — brown leather jacket with Wings of Freedom emblem on the back, white pants, knee-high brown boots. Equipped with Omni-Directional Mobility Gear — gas canisters, wire launchers, and dual ultra-hard steel blades drawn and ready. Dynamic mid-flight pose — soaring through the air with gear trailing wire cables, capes billowing. Background of a massive 50-meter Wall with colossal Titan fingers gripping the top, a Titan emerging from steam beyond. Muted military color palette — browns, greens, and grey with dramatic lighting. Dark epic anime art quality.", Category = "Anime & Gaming", IconEmoji = "\U0001F3F0", AccentColor = "#4E342E", IsActive = true, SortOrder = 105 },
            new StylePreset { Id = 346, Name = "Shinobi Ninja Style", Description = "Hidden Leaf Village ninja warrior anime", PromptTemplate = "Transform the subject into an elite shinobi ninja from the Hidden Leaf Village. CRITICAL: Preserve the subject's exact facial features and identity. Render in Naruto anime style — clean sharp character design with expressive eyes and dynamic poses. Wearing a ninja outfit — dark tactical vest over a black bodysuit. A Hidden Leaf Village forehead protector with the leaf symbol engraved in metal. Ninja tool pouch on the thigh. Performing a powerful jutsu — hands forming a ninjutsu hand sign, with swirling chakra energy around the body. A giant technique visible (Rasengan sphere, fire dragon, or shadow clones). Background of Konohagakure — the Hidden Leaf Village with Hokage Rock faces carved into the mountain. Orange, blue, and green ninja color palette. Naruto anime art quality.", Category = "Anime & Gaming", IconEmoji = "\U0001F365", AccentColor = "#FF6F00", IsActive = true, SortOrder = 106 },
            new StylePreset { Id = 347, Name = "Hero Academia Style", Description = "Quirk-powered superhero academy anime", PromptTemplate = "Transform the subject into a Pro Hero from the My Hero Academia universe. CRITICAL: Preserve the subject's exact facial features and identity. Render in MHA manga/anime style — dynamic expressive character design with detailed hero costumes. Wearing a unique custom-designed hero costume — bold color scheme, armored gauntlets, utility belt, cape or scarf, and a distinctive mask or visor. Activating their Quirk — dramatic power manifestation with visual effects (energy blasts, elemental control, physical transformation). Dynamic Plus Ultra action pose with determination. Background of U.A. High School campus or a city under villain attack. Bright bold manga color palette with action speed lines. My Hero Academia anime art quality.", Category = "Anime & Gaming", IconEmoji = "\U0001F4A5", AccentColor = "#1565C0", IsActive = true, SortOrder = 107 },
            new StylePreset { Id = 348, Name = "Devil Hunter Style", Description = "Chainsaw horror-action anime hunter", PromptTemplate = "Transform the subject into a Devil Hunter from Chainsaw Man. CRITICAL: Preserve the subject's exact facial features and identity. Render in MAPPA's gritty realistic anime style with raw visceral energy. Wearing a disheveled white shirt, loosened tie, and dark pants — battle-worn and splattered. Wild unkempt hair and intense exhausted yet determined eyes. A devil contract manifestation — chainsaw blades emerging from the arms and head, or a fiend transformation with devil horns and sharp teeth. Background of a dark Tokyo cityscape — demons emerging from shadows, destroyed city blocks, dramatic red sky. Dark gritty color palette — muted greys, blacks, with stark blood-red accents. Raw horror-action anime art quality.", Category = "Anime & Gaming", IconEmoji = "\U0001FA9A", AccentColor = "#B71C1C", IsActive = true, SortOrder = 108 },
            new StylePreset { Id = 349, Name = "Shadow Monarch Style", Description = "S-Rank Hunter shadow army commander", PromptTemplate = "Transform the subject into an S-Rank Hunter and Shadow Monarch from Solo Leveling. CRITICAL: Preserve the subject's exact facial features and identity. Render in Solo Leveling anime style — sharp handsome character design with piercing glowing blue-violet eyes radiating power. Wearing a dark black hunter outfit — long dark coat over tactical gear. Dark purple and black shadow energy swirling around the body. Commanding an army of shadow soldiers — ghostly dark warriors with glowing purple eyes rising from dark portals on the ground. One hand extended commanding the shadows. Background of a massive dungeon gate — towering stone gate with red ominous glow. Dark black and deep purple color palette with neon blue-violet highlights. Solo Leveling anime art quality.", Category = "Anime & Gaming", IconEmoji = "\U0001F464", AccentColor = "#4A148C", IsActive = true, SortOrder = 109 },
            new StylePreset { Id = 350, Name = "Elden Ring Tarnished", Description = "Dark fantasy FromSoftware warrior", PromptTemplate = "Transform the subject into a Tarnished warrior from the Elden Ring dark fantasy world. CRITICAL: Preserve the subject's exact facial features and identity. Render in FromSoftware's dark fantasy aesthetic — weathered battle-scarred character with haunted determined eyes. Wearing ornate medieval Gothic plate armor with flowing tattered red cape, engravings and runes etched into the metal. Wielding a massive glowing rune-inscribed greatsword and a brass-trimmed shield. Grace site glowing faintly nearby. Background of the Lands Between — crumbling golden cathedral, vast desolate landscape with a massive golden glowing Erdtree in the distant sky, fog-shrouded ruins. Muted dark color palette — tarnished gold, deep crimson, fog grey. Dark fantasy video game art quality.", Category = "Anime & Gaming", IconEmoji = "\U0001F5E1\uFE0F", AccentColor = "#BF360C", IsActive = true, SortOrder = 110 },
            new StylePreset { Id = 351, Name = "Hyrule Champion Style", Description = "Legend of Zelda cel-shaded adventure", PromptTemplate = "Transform the subject into a Champion of Hyrule from The Legend of Zelda. CRITICAL: Preserve the subject's exact facial features and identity. Render in Nintendo's Breath of the Wild art style — soft cel-shaded anime-inspired character design with warm natural colors. Wearing the iconic blue Champion's Tunic with Sheikah patterns, brown traveler pants and boots, and a hooded cloak. Pointed elf-like ears. Wielding a glowing blue sacred sword and a sturdy shield. Paraglider strapped to the back. Background of the vast Hyrule landscape — rolling green hills, distant volcano, castle in the distance, ancient towers on the horizon. Cel-shaded watercolor quality with soft golden hour sunlight. Pastel blue, green, and gold color palette. Nintendo art quality.", Category = "Anime & Gaming", IconEmoji = "\U0001F9DD", AccentColor = "#2E7D32", IsActive = true, SortOrder = 111 },
            new StylePreset { Id = 352, Name = "Final Fantasy Crystal", Description = "Legendary JRPG high-fantasy warrior", PromptTemplate = "Transform the subject into a legendary warrior from the Final Fantasy universe. CRITICAL: Preserve the subject's exact facial features and identity. Render in iconic Final Fantasy character design — elegant elaborate costume with impossible fantasy fashion (zippers, belts, flowing asymmetric fabrics). Elaborate spiky or flowing hairstyle with silver streaks. Wielding an oversized ornate weapon — a massive sword, gunblade, or crystal staff. Dramatic battle-ready pose with magical aura. A crystal formation or magical rune circle glowing beneath. Background of a breathtaking landscape — floating islands, a crystal tower, airships in the sky, and waterfalls cascading into clouds. Luminous fantasy color palette — crystal blue, amethyst purple, and ethereal silver. Square Enix RPG character art quality.", Category = "Anime & Gaming", IconEmoji = "\U0001F48E", AccentColor = "#5C6BC0", IsActive = true, SortOrder = 112 },
            new StylePreset { Id = 353, Name = "Genshin Vision Style", Description = "Elemental Vision holder anime open world", PromptTemplate = "Transform the subject into an elemental Vision holder from the Genshin Impact universe. CRITICAL: Preserve the subject's exact facial features and identity. Render in HoYoverse's signature anime-meets-3D art style — beautiful polished character design with intricate costume details and soft cel-shaded coloring. Wearing an elaborate fantasy outfit inspired by a specific element — flowing fabrics, armor accents, elemental motifs (fire, ice, lightning, wind, water, nature, or stone). A glowing elemental Vision gem clipped to the outfit. Activating an Elemental Burst — dramatic elemental explosion with particles. Background of Teyvat — windmills, harbors, sakura trees, or rainforest. Vibrant anime color palette matching the element. Genshin Impact splash art quality.", Category = "Anime & Gaming", IconEmoji = "\u2728", AccentColor = "#00BFA5", IsActive = true, SortOrder = 113 },

            // ── K-Culture (14) ──
            new StylePreset { Id = 360, Name = "K-Drama Lead", Description = "Korean drama romantic lead character", PromptTemplate = "Transform the subject into a Korean drama lead character. CRITICAL: Preserve the subject's exact facial features and identity. Render with flawless glass-skin K-beauty complexion with soft dewy highlights. Styled with a trendy Korean hairstyle — perfectly tousled curtain bangs or sleek side-part. Wearing a stylish Korean fashion outfit — tailored coat over a turtleneck, or a chic business-casual ensemble. Soft romantic expression — gentle smile with warm sparkling eyes. Cinematic Korean drama lighting — golden hour warm tones with soft bokeh background. Background of an iconic K-drama setting — a rooftop overlooking Seoul skyline at sunset, cherry blossom-lined street, or a cozy cafe. Romantic atmospheric haze. Warm golden, blush pink, and soft cream color palette. Korean drama promotional poster quality.", Category = "K-Culture", IconEmoji = "\U0001F3AD", AccentColor = "#E91E63", IsActive = true, SortOrder = 120 },
            new StylePreset { Id = 361, Name = "K-Pop Idol Stage", Description = "K-Pop concert stage performance style", PromptTemplate = "Transform the subject into a K-Pop idol performing on stage. CRITICAL: Preserve the subject's exact facial features and identity. Render with striking K-Pop stage makeup — bold eye look with glitter, perfectly contoured features, and flawless porcelain skin. Show-stopping hairstyle — vibrant colored (platinum, pastel pink, or electric blue) perfectly styled hair. Wearing an avant-garde stage outfit — sequined jacket, leather harness, or futuristic concept costume with metallic accents. Dynamic dance performance pose — sharp powerful choreography frozen mid-move. Background of a massive concert stage — LED screens with abstract visuals, thousands of lightsticks glowing in the audience, confetti and pyrotechnic sparks. Electric purple, hot pink, and laser blue color palette. K-Pop music video quality.", Category = "K-Culture", IconEmoji = "\U0001F3A4", AccentColor = "#AA00FF", IsActive = true, SortOrder = 121 },
            new StylePreset { Id = 362, Name = "Webtoon Hero Style", Description = "Korean digital webtoon protagonist", PromptTemplate = "Transform the subject into a Korean webtoon protagonist. CRITICAL: Preserve the subject's exact facial features and identity. Render in the distinctive Korean digital webtoon art style — clean polished linework with soft gradient cel-shading and luminous coloring. Large expressive Korean-style eyes with detailed iris reflections. Trendy Korean character design — fashionable modern outfit, perfect proportions. Dramatic close-up portrait with sparkle and screen-tone effects. Manhwa-style speed lines for dramatic emphasis. Background transitioning from realistic Seoul cityscape to fantasy — magical portals, gaming interface overlays, or romantic cherry blossom petals. Soft pastel gradients with selective vivid color pops. Professional Korean webtoon serial art quality.", Category = "K-Culture", IconEmoji = "\U0001F4F1", AccentColor = "#2979FF", IsActive = true, SortOrder = 122 },
            new StylePreset { Id = 363, Name = "Korean Hanbok Portrait", Description = "Classical traditional Korean Hanbok attire", PromptTemplate = "Transform the subject into a classical Korean Hanbok portrait. CRITICAL: Preserve the subject's exact facial features and identity. Render wearing a magnificent traditional Korean Hanbok — a beautiful jeogori (upper garment) in rich vibrant silk with delicate gold embroidery and a flowing chima (skirt) in complementary color with ornate brocade patterns. Traditional Korean hair ornaments — a binyeo hairpin and daenggi ribbon in a classic updo, or a gat hat for men. Elegant refined posture with hands folded gracefully. Background of a beautiful Korean palace courtyard — Gyeongbokgung Palace with traditional wooden architecture, curved eaves, stone courtyard, and blooming chrysanthemums. Soft natural lighting. Rich hanbok colors — cerise pink, royal blue, jade green, and gold. Classical Korean portrait painting quality.", Category = "K-Culture", IconEmoji = "\U0001F458", AccentColor = "#AD1457", IsActive = true, SortOrder = 123 },
            new StylePreset { Id = 364, Name = "Seoul Neon Street", Description = "Neon-lit Gangnam/Hongdae night style", PromptTemplate = "Transform the subject into a stylish figure in neon-lit Seoul nightlife. CRITICAL: Preserve the subject's exact facial features and identity. Render with trendy Korean street fashion — oversized designer jacket, bucket hat or face mask pulled down, chunky sneakers, and layered accessories. Cool effortless confident pose — leaning against a wall or walking through a crosswalk. Background of iconic Seoul nightlife — Gangnam or Hongdae neon-lit streets with towering LED billboards showing K-Pop advertisements, glowing Korean Hangul signage, wet rain-reflective streets creating neon mirror effects. Street food stall steam rising. Dramatic neon lighting — electric pink, blue, and purple reflections on wet pavement. Urban night photography quality with cinematic color grading.", Category = "K-Culture", IconEmoji = "\U0001F303", AccentColor = "#6200EA", IsActive = true, SortOrder = 124 },
            new StylePreset { Id = 365, Name = "K-Beauty Editorial", Description = "Flawless Korean glass-skin beauty magazine", PromptTemplate = "Transform the subject into a K-Beauty editorial magazine cover. CRITICAL: Preserve the subject's exact facial features and identity. Render with the ultimate Korean glass-skin beauty aesthetic — luminous dewy porcelain skin with a lit-from-within glow. Perfect gradient lips in coral-to-pink. Soft puppy-eye or cat-eye makeup with shimmer eyeshadow. Naturally groomed fluffy brows. Flawless skin with visible dewdrop highlights on cheekbones and nose bridge. Hair styled with soft Korean waves. Minimal jewelry — delicate pearl earrings. Clean studio beauty lighting with soft ring-light catchlights in the eyes. Pure white or soft pastel gradient background with floating flower petals. Skin-tone, blush pink, and peach color palette. Korean beauty magazine editorial photography quality.", Category = "K-Culture", IconEmoji = "\U0001F484", AccentColor = "#F48FB1", IsActive = true, SortOrder = 125 },
            new StylePreset { Id = 366, Name = "Joseon Dynasty Portrait", Description = "Historical Korean royal court portrait", PromptTemplate = "Transform the subject into a Joseon Dynasty royal court portrait. CRITICAL: Preserve the subject's exact facial features and identity. Render in traditional Korean royal portrait style. Wearing elaborate Joseon royal court attire — a dragon-embroidered gonryongpo (royal robe) in deep crimson or blue with gold thread dragons and cloud motifs, an ikseongwan (winged cap) or hwagwan (flower crown). Formal seated royal pose on a throne with a folding screen behind. Rich brocade and silk textures with intricate embroidery details. Background of a Joseon royal court — painted irworobongdo screen behind the throne, wooden palace interior with latticed doors. Muted traditional Korean color palette — deep reds, indigo, gold, and cream. Classical Joseon Dynasty portrait painting quality.", Category = "K-Culture", IconEmoji = "\U0001F451", AccentColor = "#8D6E63", IsActive = true, SortOrder = 126 },
            new StylePreset { Id = 367, Name = "K-Pop Album Cover", Description = "Conceptual K-Pop album art photo", PromptTemplate = "Transform the subject into a conceptual K-Pop album cover photo. CRITICAL: Preserve the subject's exact facial features and identity. Render with high-concept K-Pop visual aesthetic — ethereal otherworldly styling with avant-garde fashion. Artistic editorial makeup with graphic elements — rhinestones, metallic accents, or painted designs on the face. Wearing a conceptual outfit — either dark moody (black leather, chains, dark romanticism) or dreamy ethereal (flowing white fabrics, angel wings, crystals). Artistic pose with strong visual composition. Background of a surreal K-Pop set — floating geometric shapes, holographic surfaces, otherworldly landscapes, or abstract color gradients. High-fashion editorial color grading. K-Pop album concept photo quality with magazine-level retouching.", Category = "K-Culture", IconEmoji = "\U0001F4BF", AccentColor = "#FF6D00", IsActive = true, SortOrder = 127 },
            new StylePreset { Id = 368, Name = "Korean Folklore", Description = "Mystical Korean mythology Gumiho spirit", PromptTemplate = "Transform the subject into a character from Korean folklore and mythology. CRITICAL: Preserve the subject's exact facial features and identity. Render as a mystical Gumiho (nine-tailed fox spirit) with ethereal fox ears, nine flowing fox tails made of blue-white spirit fire, and luminous golden eyes with vertical slit pupils. Wearing an elegant white and red traditional hanbok that flows and transforms into fox-fire at the edges. Holding a yeouiju (magical fox bead) glowing with blue mystical energy. Supernatural beauty with an enchanting yet dangerous expression. Background of a moonlit Korean mountain temple — ancient pine trees, stone pagodas, misty valleys, full moon casting silver light. Fox-fire wisps floating in the air. Blue-white, silver, and deep red color palette. Korean folklore meets modern fantasy illustration quality.", Category = "K-Culture", IconEmoji = "\U0001F98A", AccentColor = "#FF5722", IsActive = true, SortOrder = 128 },
            new StylePreset { Id = 369, Name = "Manhwa Action Style", Description = "Korean action manga protagonist", PromptTemplate = "Transform the subject into an action manhwa (Korean manga) protagonist. CRITICAL: Preserve the subject's exact facial features and identity. Render in dynamic Korean manhwa webtoon action style — sharp angular character design with intense determined eyes and sleek modern features. Dark hair with dramatic shading. Wearing a stylish modern combat outfit — tactical jacket, dark pants, combat boots with subtle magical or tech enhancements glowing. In the middle of an explosive action scene — delivering a powerful punch with shockwave impact rings. Dynamic speed lines and impact effects radiating outward. Background of an urban Seoul battlefield — cracked streets, shattered buildings, dungeon gate portals opening in the sky. High-contrast dramatic color palette — dark blacks with vivid red and electric blue highlights. Korean manhwa action art quality.", Category = "K-Culture", IconEmoji = "\u26A1", AccentColor = "#D50000", IsActive = true, SortOrder = 129 },
            new StylePreset { Id = 370, Name = "Korean Cafe Aesthetic", Description = "Cozy Seoul cafe lifestyle illustration", PromptTemplate = "Transform the subject into a cozy Korean cafe aesthetic scene. CRITICAL: Preserve the subject's exact facial features and identity. Render with warm soft Korean illustration style — gentle linework with watercolor-like pastel coloring. Wearing a comfortable chic outfit — oversized knit sweater, beret, or cozy scarf. Sitting in a Seoul cafe — holding a beautifully crafted latte art coffee cup, reading a book with a slice of Korean honey toast nearby. Soft content smile with warm eyes. Background of an aesthetic Korean cafe interior — exposed brick walls, warm Edison bulb string lights, wooden furniture, green hanging plants, floor-to-ceiling windows showing a rainy Seoul street. Warm cozy color palette — cream, caramel brown, sage green, and blush pink. Korean lifestyle illustration quality.", Category = "K-Culture", IconEmoji = "\u2615", AccentColor = "#795548", IsActive = true, SortOrder = 130 },
            new StylePreset { Id = 371, Name = "Chibi K-Pop", Description = "Adorable chibi K-Pop idol character", PromptTemplate = "Transform the subject into an adorable chibi K-Pop idol character. CRITICAL: Preserve the subject's facial likeness and identity in chibi form. Render in Korean chibi (SD — super deformed) style — enormous head (3:1 ratio to body), giant sparkly eyes with star-shaped highlights, tiny adorable body with stubby limbs. Cute K-Pop stage outfit miniaturized — sparkly jacket, lightstick accessory, and tiny headset microphone. Performing an iconic K-Pop heart pose — finger heart, double heart, or aegyo pose with blushing cheeks. Surrounded by cute floating elements — hearts, stars, music notes, sparkles, mini lightsticks. Background of pastel concert stage with chibi audience holding lightsticks. Pastel candy color palette — bubblegum pink, baby blue, lavender, and mint. Adorable Korean fan-art chibi illustration quality.", Category = "K-Culture", IconEmoji = "\U0001F9F8", AccentColor = "#EC407A", IsActive = true, SortOrder = 131 },
            new StylePreset { Id = 372, Name = "Korean Horror", Description = "Atmospheric Korean horror cinema style", PromptTemplate = "Transform the subject into a scene from Korean horror cinema. CRITICAL: Preserve the subject's exact facial features and identity. Render in atmospheric Korean horror film aesthetic — pale desaturated skin with dark shadows under the eyes, wet black hair partially covering the face. Wearing a simple white or school uniform outfit, dampened and slightly tattered. A subtle uncanny expression — wide unblinking eyes staring slightly off-center, ambiguous between fear and menace. A single hand reaching forward from darkness. Background of a dark rain-soaked apartment corridor with flickering fluorescent lights, or an abandoned school hallway with peeling wallpaper. Water stains creeping down walls. A ghostly reflection in a window. Desaturated cold color palette — pale blue-grey, sickly green, deep black with a single red accent. Korean horror film cinematography quality.", Category = "K-Culture", IconEmoji = "\U0001F47B", AccentColor = "#37474F", IsActive = true, SortOrder = 132 },
            new StylePreset { Id = 373, Name = "Korean Ink Brush", Description = "Traditional Korean sumi ink brush painting", PromptTemplate = "Transform the subject into a traditional Korean ink brush painting (sumukhwa). CRITICAL: Preserve the subject's facial likeness and identity. Render in elegant Korean sumi ink brush painting style — bold expressive black ink brushstrokes on textured hanji (Korean mulberry paper). Varying brush pressure creating thick-to-thin calligraphic lines — bold confident strokes for the main form with delicate thin strokes for details. Minimal color — primarily black ink with subtle washes of grey. A sparse touch of red cinnabar seal stamp in the corner. Negative space used masterfully — the empty paper as important as the painted areas. Background of natural Korean landscape elements — pine branches, bamboo, plum blossoms, or misty mountains in sansuhwa style. Monochrome ink with occasional pale blue-green or warm ochre wash accents. Traditional Korean literati painting quality.", Category = "K-Culture", IconEmoji = "\U0001F58C\uFE0F", AccentColor = "#263238", IsActive = true, SortOrder = 133 },

            // ── PhotoArts ──
            new StylePreset { Id = 434, Name = "Portrait Oil Painting", Description = "Expressive oil painting portrait on canvas", PromptTemplate = "A professional portrait of [subject] rendered as an expressive oil painting on canvas. High contrast, thick impasto brushwork in the background, and fine-detail blending on the face. Rich, warm color palette. The lighting should be dramatic, highlighting the contours of the face like a studio portrait. Artistic, painterly, textured, and sophisticated.", Category = "PhotoArts", IconEmoji = "\U0001F5BC\uFE0F", AccentColor = "#8D6E63", IsActive = true, SortOrder = 156 },
            new StylePreset { Id = 435, Name = "Smudge Oil Portrait", Description = "Ultra-smooth digital smudge painting with cinematic glow", PromptTemplate = "A high-quality digital oil painting of [subject]. The style is \"smudge painting\" with ultra-smooth skin textures, vibrant saturation, and visible but soft brushstrokes. The background is a soft-focus abstract bokeh with warm, moody lighting. Professional digital art, sharp facial features, deep shadows, and an artistic glow on the skin. 8k resolution, cinematic lighting.", Category = "PhotoArts", IconEmoji = "\U0001F3A8", AccentColor = "#E65100", IsActive = true, SortOrder = 157 },
            new StylePreset { Id = 436, Name = "Vexel Art Portrait", Description = "Clean vexel illustration with detailed hair and vibrant colors", PromptTemplate = "A stylized digital illustration of [subject]. Clean lines, smooth color gradients, and a \"vexel art\" aesthetic. The hair is highly detailed with individual light-catching strands. Simple, elegant, blurred background to make the subject pop. High-end retouching style, vibrant colors, and sharp, soulful eyes.", Category = "PhotoArts", IconEmoji = "\u2728", AccentColor = "#7C4DFF", IsActive = true, SortOrder = 158 },
            new StylePreset { Id = 437, Name = "Vibrant Digital Oil", Description = "Vibrant digital oil painting with dramatic warm lighting", PromptTemplate = "A vibrant, expressive digital oil painting of [subject]. The art style features smooth, blended brushstrokes and high-gloss textures, with more suttled pinkish tone particularly on the skin and lips. Use a warm, dramatic lighting scheme with strong golden-orange highlights on one side of the face and deep purple or charcoal shadows in the background. The person has dark, voluminous, hair that blends softly into a textured, painterly backdrop. Focus on hyper-realistic details in the eyes and teeth while maintaining a buttery 'oil paint' finish throughout the composition.", Category = "PhotoArts", IconEmoji = "\U0001F31F", AccentColor = "#FF8F00", IsActive = true, SortOrder = 159 },

            // ── PhotoCollage (new batch) ──
            new StylePreset { Id = 438, Name = "Pastoral Polaroid", Description = "Polaroid frames scattered over a dreamy countryside backdrop", PromptTemplate = "DO NOT simply reproduce the source photo. You MUST generate a BRAND NEW composite image that is a POLAROID COLLAGE OVER A FULL-BLEED BACKGROUND PHOTO on a vertical 2:3 portrait canvas. Use the person from the source photo — preserve their EXACT face, hair, and appearance in every panel. BACKGROUND: A single large full-bleed lifestyle photograph filling the entire canvas — the same person standing or walking in a scenic countryside setting with a wooden fence, green meadows, and warm golden-hour sunlight. Soft warm vintage colour grading — faded golds, blush pinks, sage greens. The person wears a charming outfit like a gingham dress or linen blouse, holding wildflowers or a straw hat. THREE POLAROID FRAMES overlaid on the LEFT SIDE of the canvas, slightly overlapping, each tilted at different casual angles (3-8 degrees). Each polaroid has a thick white instant-photo border (wider at the bottom). Polaroid 1 (top-left area): a close-up of the person sitting on a blanket, soft dreamy expression, flowers in hair. Polaroid 2 (middle-left area): a three-quarter portrait, person smelling a bouquet of wildflowers, gentle smile. Polaroid 3 (bottom-left area): the person from behind or side, arranging flowers on a picnic blanket, candid moment. Each polaroid casts a subtle drop shadow onto the background. COLOUR GRADING: unified warm pastoral palette — soft peach, cream, blush pink, sage green, warm gold. Subtle film grain and slight vignette across the entire image. The final output must look like physical polaroid prints casually placed on top of a printed background photograph.", Category = "PhotoCollage", IconEmoji = "\U0001F33B", AccentColor = "#F8BBD0", IsActive = true, SortOrder = 160 },
            new StylePreset { Id = 439, Name = "Nature Circle Grid", Description = "Diagonal grid with central circle showcasing nature scenes", PromptTemplate = "DO NOT reproduce the source photo. Generate a BRAND NEW GEOMETRIC COLLAGE on a vertical 2:3 portrait canvas. Use the person from the source photo — preserve their EXACT face, hair, and appearance. LAYOUT: The canvas is divided into 5 panels by DIAGONAL WHITE LINES (approximately 4-5px thick) radiating from the centre, creating 4 triangular/trapezoidal corner sections. In the EXACT CENTRE of the canvas sits a LARGE CIRCLE (approximately 40% of canvas width) with a thick white circular border (4-5px). CORNER PANELS — Top-left triangle: lush green forest scene — tall pine trees beside a calm lake, the person standing small among the trees, peaceful contemplation. Deep green tones. Top-right triangle: dramatic mountain landscape — misty snow-capped peaks with overcast sky, the person hiking a trail, sense of adventure. Cool grey-blue tones. Bottom-left triangle: dramatic natural formation — a cave entrance or rocky gorge with green moss, the person exploring, sense of wonder. Warm earthy greens and browns. Bottom-right triangle: volcanic or coastal landscape — distant mountain with tropical vegetation in foreground, the person gazing at the vista. Teal and warm brown tones. CENTRE CIRCLE: a beautiful panoramic lake scene — crystal clear water reflecting blue sky and surrounding green hills, the person at the water's edge, serene moment. Vibrant blue and green. WHITE DIVIDERS between all panels must be clean, crisp, and consistent width. No decorations or text. COLOUR PALETTE: rich natural greens, deep blues, cool greys, earthy browns — each panel has its own dominant tone but all share a cohesive nature photography aesthetic. The final image must look like a professionally designed geometric photo collage of nature adventures.", Category = "PhotoCollage", IconEmoji = "\U0001F332", AccentColor = "#2E7D32", IsActive = true, SortOrder = 161 },
            new StylePreset { Id = 440, Name = "Fashion Wave", Description = "Curved S-wave panels with editorial fashion photography", PromptTemplate = "DO NOT reproduce the source photo. Generate a BRAND NEW FASHION EDITORIAL COLLAGE on a vertical 2:3 portrait canvas. Use the person from the source photo — preserve their EXACT face, hair, and appearance. LAYOUT: The canvas is divided into 5-6 panels separated by smooth CURVED S-WAVE DIVIDERS — elegant flowing sinusoidal curves that sweep from left to right edge, creating organic ribbon-like horizontal bands across the canvas. The curves should be smooth and flowing like gentle waves, NOT straight lines. PANELS — Panel 1 (top, largest ~30%): a dramatic hero portrait — the subject in an elegant dark outfit, flowing hair, confident pose, sophisticated neutral background. Rich warm colour with cinematic lighting. Panel 2 (upper-middle, ~15%): a black-and-white editorial shot — the subject seated on a chair, dynamic pose with interesting arm placement, dramatic studio lighting with hard shadows. High contrast B&W. Panel 3 (middle, ~20%): another black-and-white shot — the subject in motion, flowing skirt or dramatic gesture, artistic movement blur, high fashion editorial style. Panel 4 (lower-middle, ~15%): colour shot — the subject in an urban setting, walking past elegant architecture, street-style candid feeling. Warm muted tones. Panel 5 (bottom, ~20%): the subject in profile or three-quarter view, looking away, moody atmospheric lighting, dark sophisticated setting. CRITICAL: The curved wave dividers must be smooth and flowing. Some panels are full colour, some are black-and-white — this contrast is essential. COLOUR PALETTE: dark sophisticated — charcoal, warm taupe, cream, with muted warm accents. Black-and-white panels should be true monochrome with rich tonal range. Overall mood: high-fashion editorial magazine spread.", Category = "PhotoCollage", IconEmoji = "\U0001F5DE\uFE0F", AccentColor = "#37474F", IsActive = true, SortOrder = 162 },
            new StylePreset { Id = 441, Name = "Graduation Celebration", Description = "Large hero panel with stacked milestone moments", PromptTemplate = "DO NOT reproduce the source photo. Generate a BRAND NEW GRADUATION CELEBRATION COLLAGE on a vertical 2:3 portrait canvas. Use the person from the source photo — preserve their EXACT face, hair, and appearance. LAYOUT: The canvas is divided into TWO COLUMNS. LEFT COLUMN (approximately 55-60% width): A single LARGE hero photograph filling the entire left side from top to bottom. RIGHT COLUMN (approximately 40-45% width): THREE stacked horizontal panels of roughly equal height, separated by thin white gaps (3px). LEFT HERO PANEL: The subject photographed from behind, wearing a graduation cap and gown, walking along a tree-lined autumn campus path. Beautiful warm golden-hour backlighting creating a silhouette rim-light effect. Fallen autumn leaves on the ground — warm oranges, yellows, reds. Sense of stepping forward into the future. RIGHT TOP PANEL: The subject in cap and gown, facing camera, holding a diploma with a proud beaming smile. Indoor or outdoor ceremony setting, warm lighting. RIGHT MIDDLE PANEL: A candid celebration moment — the subject tossing the graduation cap in the air, arms raised in joy, big laugh. Blue sky or confetti background. RIGHT BOTTOM PANEL: A close-up portrait — the subject smiling warmly and genuinely, tassel hanging on the cap, soft bokeh background, emotional happy moment. COLOUR GRADING: warm golden autumn palette throughout — amber, burnt orange, warm brown, cream. Slightly desaturated and cohesive across all panels. Thin white borders separate the right panels. No text or decorations. The final image must look like a professional graduation photo collage celebrating achievement.", Category = "PhotoCollage", IconEmoji = "\U0001F393", AccentColor = "#F57F17", IsActive = true, SortOrder = 163 },
            new StylePreset { Id = 442, Name = "Beach Geometric", Description = "Dynamic diagonal triangular cuts with vibrant beach scenes", PromptTemplate = "DO NOT reproduce the source photo. Generate a BRAND NEW GEOMETRIC BEACH COLLAGE on a vertical 2:3 portrait canvas. Use the person from the source photo — preserve their EXACT face, hair, and appearance. IMPORTANT: The person MUST appear in at least 5 of the 6 sections in different poses and beach activities. LAYOUT: The canvas is divided into 6 triangular and trapezoidal sections by SHARP DIAGONAL LINES crossing the canvas at various angles, creating a dynamic geometric mosaic. The dividers are thin white lines (3-4px). The diagonal cuts should create a mix of triangles and irregular quadrilaterals — like shards of a broken mirror reassembled. PANELS — Section 1 (top-left triangle): overhead beach view with white umbrellas and thatched palapas, turquoise water, the person walking barefoot on white sand. Bright and airy. Section 2 (top-right trapezoid): the person standing at a tropical beach resort — leaning against a palm tree, wearing stylish beachwear, crystal clear turquoise water behind them. Vibrant saturated blues and greens. Section 3 (centre-left): the person in a summer outfit and sun hat, relaxing on the beach, golden warm lighting, candid smile. Warm yellows and whites. Section 4 (centre-right): the person sitting at the water's edge with turquoise waves gently reaching their legs, holding a tropical cocktail, looking at the camera with a relaxed smile. Vivid teal and aqua tones. Section 5 (bottom-left triangle): the person splashing through shallow ocean waves with white foam, joyful and playful, dynamic movement. Dynamic water texture. Section 6 (bottom-right triangle): the person silhouetted or warmly lit against a panoramic sunset beach view — golden sand stretching to the horizon, tropical hillside in background, warm sunset glow. COLOUR PALETTE: vibrant tropical — turquoise, aqua, golden yellow, warm sand beige, bright white. High saturation and contrast. Each section should feel like a different vibrant beach photograph featuring the same person in a different moment. The final image must look like a dynamic geometric photo mosaic of a tropical beach vacation.", Category = "PhotoCollage", IconEmoji = "\U0001F3D6\uFE0F", AccentColor = "#00ACC1", IsActive = true, SortOrder = 164 },
            new StylePreset { Id = 443, Name = "Torn Paper Mood Board", Description = "Ripped paper edges with moody fashion editorial aesthetic", PromptTemplate = "DO NOT reproduce the source photo. Generate a BRAND NEW TORN PAPER MOOD BOARD COLLAGE on a vertical 2:3 portrait canvas. Use the person from the source photo — preserve their EXACT face, hair, and appearance. LAYOUT: 4-5 photographs arranged in an organic, overlapping scrapbook layout. Each photo has IRREGULAR TORN/RIPPED PAPER EDGES — jagged, uneven tears with visible white paper fibres along the rip lines. Photos overlap casually at slight angles as if ripped from magazines and arranged on a surface. PHOTOS — Photo 1 (top-left, largest ~35%): two shots of the subject side by side or a wide editorial pose — full body in a chic all-black outfit (blazer, belt, wide-leg trousers), strong confident stance. Warm neutral studio background. Photo 2 (top-right area): extreme close-up of hands wearing delicate gold rings and bracelets, elegant manicure, reaching or gesturing artistically. Warm skin tones against muted background. Photo 3 (bottom-left): close-up detail shot — the subject's profile showing a statement earring, elegant hairstyle, neck and jawline. Soft warm side lighting. Photo 4 (bottom-right): the subject in another sophisticated dark outfit, candid three-quarter pose, carrying a designer bag, urban backdrop slightly visible. TEXT ELEMENTS: 1-2 small torn paper strips with hand-stamped or typewriter-style text — words like 'fine and detail' or 'AMAZING' in a grungy distressed font. These text strips are small accent pieces, not dominant. BACKGROUND: warm beige/cream paper texture visible through the gaps between torn photos. COLOUR PALETTE: dark moody fashion — black, charcoal, warm beige, cream, gold accents. The photos themselves are warm-toned with muted saturation. Overall mood: high-end fashion mood board or editorial tear sheet with an artisanal handmade feel.", Category = "PhotoCollage", IconEmoji = "\U0001F4CB", AccentColor = "#5D4037", IsActive = true, SortOrder = 165 },
            new StylePreset { Id = 444, Name = "Wedding Calendar", Description = "Dark elegant wedding collage with calendar grid and polaroid moments", PromptTemplate = "DO NOT reproduce the source photo. Generate a BRAND NEW WEDDING CALENDAR COLLAGE on a vertical 2:3 portrait canvas. Use the subject(s) from the source photo — preserve their EXACT face(s), hair, and appearance. IMPORTANT: Include ONLY the exact number of people from the source image. If the source has 1 person, show only that person in elegant wedding attire throughout. If the source has 2 people, show them as a couple. LAYOUT: The canvas has a DARK BLACK/DEEP CHARCOAL BACKGROUND. RIGHT SIDE (55-60% width): A single large HERO PHOTOGRAPH of the subject(s) in traditional wedding attire — elegant formal wear, vibrant silk saree with gold jewellery or classic suit/sherwani. Seated in a lush garden or outdoor setting with green foliage, soft lantern glow, and romantic ambient lighting. Warm and intimate. This photo extends from top to about 75% of the canvas height. LEFT SIDE (40-45% width): 4-5 SMALLER POLAROID-STYLE PHOTOS stacked vertically, each slightly tilted at casual angles (2-6 degrees) with thick white instant-photo borders. Each polaroid shows a COMPLETELY DIFFERENT wedding moment: Polaroid 1 (top): a dramatic outdoor shot — flowing veil or dupatta caught in the wind, grand architectural backdrop. Polaroid 2: glamorous black evening attire at a pre-wedding event, fairy lights behind. Polaroid 3: a close-up emotional moment — soft warm lighting, intimate expression. Polaroid 4: a fun candid pose — dancing, laughing, or playful moment at the celebration. Polaroid 5 (bottom): a formal portrait with traditional decor — marigold garlands, ornate mandap background. Each polaroid casts a subtle drop shadow on the dark background. BOTTOM-LEFT AREA: {{CALENDAR}} BOTTOM-RIGHT AREA: Elegant calligraphy text reading '{{OCCASION}}' in warm gold or cream script font. Below that, '{{MESSAGE}}' in a decorative script with small ornamental flourishes. COLOUR PALETTE: deep black background, warm gold accents, vibrant colours (blue, red, green), white polaroid borders, warm skin tones. Overall mood: elegant, romantic, celebratory wedding.", Category = "PhotoCollage", IconEmoji = "\U0001F4C5", AccentColor = "#FFD700", IsActive = true, SortOrder = 166 },
            new StylePreset { Id = 445, Name = "Birthday Calendar", Description = "Soft floral birthday collage with watercolor frames and calendar", PromptTemplate = "DO NOT reproduce the source photo. Generate a BRAND NEW BIRTHDAY CALENDAR COLLAGE on a vertical 2:3 portrait canvas. Use the person from the source photo — preserve their EXACT face, hair, and appearance. BACKGROUND: Soft white/cream paper texture with delicate watercolour FLORAL DECORATIONS in the corners — soft pink roses, blush peonies, dusty rose blooms with sage green leaves and small golden leaf sprigs scattered organically. The flowers are concentrated in the TOP-RIGHT and BOTTOM-LEFT corners, fading gently into the white background. PHOTO LAYOUT: THREE CIRCULAR PHOTOS arranged in a triangular composition on the canvas. Each circle has a soft WATERCOLOUR SPLASH BORDER — irregular artistic paint splatter edges in muted warm tones (soft brown, dusty rose, warm grey) that bleed outward from the circle, creating a hand-painted frame effect. Circle 1 (top-left, largest ~35% canvas width): the subject outdoors in a beautiful outfit, soft golden bokeh background, dreamy three-quarter portrait with warm autumn light. Circle 2 (middle-right, medium ~30%): a close-up portrait of the subject with a big joyful smile, sparkling eyes, natural warm lighting. Circle 3 (bottom-centre, medium ~28%): the subject in a different outfit, full or three-quarter body, elegant pose, perhaps seated or in a playful candid moment. LEFT SIDE (below Circle 1): {{CALENDAR}} Simple elegant typography in dark grey. TOP-RIGHT AREA (above or near Circle 2): Large elegant CALLIGRAPHY TEXT reading 'Happy Birthday' in flowing script — dark charcoal or soft black ink, with the name '{{MESSAGE}}' below in matching calligraphic style. BOTTOM AREA: A handwritten-style QUOTE or birthday wish in elegant italic cursive — warm dark grey text, 2-3 lines of heartfelt message. Small decorative flourish underneath. COLOUR PALETTE: soft white, cream, dusty rose pink, sage green, warm grey, golden accents. Watercolour texture throughout. Overall mood: soft, feminine, elegant, celebratory.", Category = "PhotoCollage", IconEmoji = "\U0001F382", AccentColor = "#F48FB1", IsActive = true, SortOrder = 167 },
            new StylePreset { Id = 446, Name = "Reception Double Exposure", Description = "Cinematic movie-poster style with smoky double exposure overlay", PromptTemplate = "DO NOT reproduce the source photo. Generate a BRAND NEW CINEMATIC RECEPTION POSTER on a vertical 2:3 portrait canvas. Use the subject(s) from the source photo — preserve their EXACT face(s), hair, and appearance. IMPORTANT: Include ONLY the exact number of people from the source image. If the source has 1 person, show only that person throughout — use a single dramatic face in the double exposure and a single elegant portrait below. If the source has 2 people, show them as a couple. This should look like a MOVIE POSTER for a celebration/reception. LAYOUT — TOP HALF (60% of canvas): A dramatic DOUBLE EXPOSURE / OVERLAY effect. A large, softly DESATURATED close-up of the subject's face(s) in PROFILE — rendered in muted blue-grey/silver monochrome tones, large scale, filling the upper portion. The edges fade and dissolve into smoke, mist, or soft particle effects. The face(s) should be semi-transparent, blending into the dark background like a ghostly cinematic overlay. BOTTOM HALF (40% of canvas): A smaller but VIVID, FULL-COLOUR photograph of the subject(s) — in a gorgeous embellished outfit (lehenga, gown, saree with heavy jewellery, or sharp suit/sherwani). Elegant pose, smiling warmly. Professional studio-quality lighting with warm golden tones. This photo is crisp and vibrant, contrasting with the desaturated overlay above. TRANSITION between top and bottom: Smooth gradient dissolve with smoky/misty particles, soft bokeh light orbs (warm gold and cool blue), creating a dreamy cinematic blend. No hard edges. CENTRE TEXT AREA (between the overlay and colour photo): Elegant script text — '{{MESSAGE}}' in flowing calligraphy, warm gold or cream colour. Below that, the word 'RECEPTION' in large, wide-spaced, elegant serif or art-deco uppercase font — gold metallic effect with subtle glow. BACKGROUND: Deep dark charcoal to black gradient, with subtle blue-teal tint in the shadows. Floating bokeh light particles scattered throughout. COLOUR PALETTE: dark charcoal, silver-grey (for double exposure), warm gold (for text and highlights), rich warm tones in the colour photo. Overall mood: cinematic, dramatic, romantic, premium reception invitation.", Category = "PhotoCollage", IconEmoji = "\U0001F3AC", AccentColor = "#263238", IsActive = true, SortOrder = 168 },

            // ── PhotoCollage (strip/poster/motherhood batch) ──
            new StylePreset { Id = 447, Name = "Wedding Strip Collage", Description = "Vertical photo strips with hero shot and elegant text overlay", PromptTemplate = "DO NOT reproduce the source photo. Generate a BRAND NEW WEDDING STRIP COLLAGE on a vertical 2:3 portrait canvas. Use the subject(s) from the source photo — preserve their EXACT face(s), hair, and appearance in every panel. IMPORTANT: Include ONLY the exact number of people from the source image. If the source has 1 person, show only that person in different wedding outfits and poses throughout. If the source has 2 people, show them together as a couple. BACKGROUND: Soft cream/ivory textured linen canvas. LAYOUT — TOP HALF (55% of canvas): THREE VERTICAL RECTANGULAR PHOTO STRIPS arranged side by side with thin white gaps (4px) between them. Each strip is tall and narrow (roughly 30% canvas width × 50% canvas height). Strip 1 (left): the subject(s) in formal wedding attire — luxurious bridal outfit or classic suit/sherwani — standing in an ornate decorated venue with warm golden lighting, elegant chandeliers. Three-quarter body shot, elegant pose. Strip 2 (centre): a candid outdoor moment — walking through a beautiful garden or along a scenic path with soft golden-hour sunlight. Different outfit or slightly different styling from strip 1. Joyful natural expressions. Strip 3 (right): a close-up portrait — intimate expression, soft dreamy bokeh background, warm tones. Different setting from the other two strips. BOTTOM HALF (45% of canvas): A single LARGE HERO PHOTOGRAPH of the subject(s) — full body or three-quarter, in stunning formal attire, standing in a grand setting (palace steps, ornate archway, elegant ballroom). The top edge of this hero photo OVERLAPS slightly with the bottom edges of the three strips above, creating depth. Professional dramatic lighting, rich warm tones. TEXT OVERLAYS: Large translucent calligraphy text '{{MESSAGE}}' elegantly overlaid across the centre of the canvas in warm gold or soft white — the text flows gracefully over the transition between strips and hero photo. COLOUR PALETTE: warm ivory, cream, soft gold, rich warm skin tones, blush pink accents. Unified warm colour grading across all panels. Overall mood: elegant, romantic, premium wedding album.", Category = "PhotoCollage", IconEmoji = "\U0001F492", AccentColor = "#D4AF37", IsActive = true, SortOrder = 169 },
            new StylePreset { Id = 448, Name = "True Love Smoke Poster", Description = "Dramatic golden smoke double-tone poster with bold love text", PromptTemplate = "DO NOT reproduce the source photo. Generate a BRAND NEW DRAMATIC LOVE POSTER on a vertical 2:3 portrait canvas. Use the subject(s) from the source photo — preserve their EXACT face(s), hair, and appearance. IMPORTANT: Include ONLY the exact number of people from the source image. If the source has 1 person, show only that person in both sections — a solo dramatic profile top and solo portrait bottom. If the source has 2 people, show them together. LAYOUT — TOP HALF (50-55% of canvas): A large desaturated close-up of the subject(s) in PROFILE — rendered in muted warm grey/sepia tones, slightly faded and dreamlike. Dramatic GOLDEN-YELLOW SMOKE and fine particle effects dissolve upward from the bottom of this section, partially obscuring and blending with the subject's form(s). The smoke is thick, swirling, and vivid amber/gold in colour, creating a magical dissolving effect. The face(s) emerge from the smoke with an intense emotional gaze. The overall tone is cinematic and atmospheric. TOP-RIGHT CORNER: Bold elegant text '{{OCCASION}}' in large stylish serif or script font — cream or warm gold colour. Below it in smaller refined type: '{{MESSAGE}}'. BOTTOM HALF (45-50% of canvas): A VIVID FULL-COLOUR photograph of the same subject(s) — in an elegant dark outfit (black dress, formal wear, or complementary dark attire). Confident warm expression, holding flowers (roses or a bouquet). The background is a rich VIVID AMBER/GOLDEN-YELLOW gradient, warm and glowing. Professional studio-quality lighting with warm golden highlights. This bottom image is crisp, saturated, and vibrant — dramatically contrasting with the desaturated top. TRANSITION: The golden smoke from the top section gradually blends into the warm background of the bottom section. No hard dividing line — a smooth cinematic gradient dissolve with floating golden particles and soft bokeh orbs. COLOUR PALETTE: deep warm gold, amber, rich yellow, charcoal grey (in desaturated top), dark black outfits, warm skin tones. Overall mood: dramatic, cinematic love story poster.", Category = "PhotoCollage", IconEmoji = "\U0001F49B", AccentColor = "#FFB300", IsActive = true, SortOrder = 170 },
            new StylePreset { Id = 449, Name = "Birthday Strip Portrait", Description = "Clean white layout with full-body shot and angled photo strips", PromptTemplate = "DO NOT reproduce the source photo. Generate a BRAND NEW BIRTHDAY STRIP PORTRAIT COLLAGE on a vertical 2:3 portrait canvas. Use the person from the source photo — preserve their EXACT face, hair, and appearance in every panel. BACKGROUND: Clean pure WHITE background with very subtle soft shadows. LAYOUT — LEFT SIDE (40-45% of canvas width): A single FULL-BODY PORTRAIT of the subject — seated or standing in an elegant outfit (stylish dress, sharp casual wear, or formal attire), relaxed confident pose. Professional studio lighting, soft shadows on the white background. Vibrant full colour with warm skin tones. RIGHT SIDE (55-60% of canvas width): 2-3 HORIZONTAL RECTANGULAR PHOTO STRIPS arranged at slight angles (3-7 degrees tilt), stacked vertically with casual spacing. Each strip is a different photo: Strip 1 (top, slight clockwise tilt): a COLOUR candid shot — the subject laughing or in a joyful pose, different outfit or setting from the main portrait. Warm golden tones. Strip 2 (middle, slight counter-clockwise tilt): a BLACK-AND-WHITE artistic portrait — the subject in a dramatic or contemplative pose, high contrast monochrome, studio lighting. Strip 3 (bottom, slight clockwise tilt): another COLOUR lifestyle shot — the subject outdoors or in a different setting, bright and cheerful, natural light. Each strip has a subtle drop shadow on the white background. DECORATIVE ELEMENTS: A small decorative butterfly or floral element near the strips — delicate, not overwhelming. BOTTOM-RIGHT AREA: Beautiful decorative calligraphy text 'Happy Birthday' in an elegant flowing script — warm gold, rose gold, or dark charcoal colour. Below it: '{{MESSAGE}}' in matching but slightly smaller decorative font. A thin ornamental swirl or flourish underneath. COLOUR PALETTE: clean white, warm skin tones, pops of colour from outfits, gold or rose gold text accents. Mix of colour and B&W photos for visual interest. Overall mood: clean, modern, elegant birthday celebration.", Category = "PhotoCollage", IconEmoji = "\U0001F381", AccentColor = "#E91E63", IsActive = true, SortOrder = 171 },
            new StylePreset { Id = 450, Name = "Crystal Glass Figurine", Description = "Miniature transparent glass sculpture in rain", PromptTemplate = "Transform the subject(s) into a stunning MINIATURE CRYSTAL GLASS FIGURINE sculpture. Render ONLY the exact number of people from the source photo as delicate transparent crystal/glass statuettes — approximately 6-8 inches tall, standing under a tiny clear glass umbrella. If the source has 1 person, create 1 figurine only. If the source has 2 people, create 2 figurines together. The glass figures capture the exact facial features and appearance of the subject(s). The crystal is PERFECTLY TRANSPARENT with subtle internal refractions, prismatic rainbow light catches, and smooth polished surfaces. Fine glass details: flowing hair strands in glass, delicate clothing folds, tiny glass flowers or accessories. The figurine(s) stand on a small reflective surface — wet cobblestones or a polished stone base. ENVIRONMENT: Gentle rain falling around the figurine(s) — individual water droplets visible, some drops splashing on the umbrella and the surface around them. Scattered autumn leaves (tiny, in warm orange and red) around the base. The background is a soft dreamy BOKEH — warm golden and teal-green out-of-focus lights suggesting an autumn evening park scene. Shallow depth of field, macro photography style as if shot with a 100mm macro lens at f/2.8. LIGHTING: Warm golden backlight creating rim lighting on the glass edges, soft fill light illuminating the internal crystal structure, tiny sparkles and light refractions throughout. Water droplets on the glass surface catching the light. COLOUR PALETTE: crystal clear glass, warm amber/gold backlighting, cool teal-green bokeh, warm autumn leaf colours, silver rain streaks. The overall image should look like a professional macro photograph of an exquisite hand-blown glass art piece.", Category = "Artistic", IconEmoji = "\U0001F48E", AccentColor = "#80DEEA", IsActive = true, SortOrder = 172 },
            // ── PhotoCollage (birthday calendar/double-exposure batch) ──
            new StylePreset { Id = 452, Name = "Dark Birthday Calendar", Description = "Dark cinematic birthday collage with polaroids, hero shot and calendar grid", PromptTemplate = "DO NOT reproduce the source photo. Generate a BRAND NEW DARK BIRTHDAY CALENDAR COLLAGE on a vertical 2:3 portrait canvas. Use the person from the source photo — preserve their EXACT face, hair, and appearance in every panel. LAYOUT: The canvas has a DARK BLACK/DEEP CHARCOAL BACKGROUND with a subtle vignette. RIGHT SIDE (55-60% width): A single large HERO PHOTOGRAPH of the subject — the person in a stylish outfit, outdoors in a colourful or scenic setting (urban street, garden, park). Natural warm lighting with a slight cinematic colour grade. The subject should be looking towards the camera with a warm, confident expression. This photo extends from the top to about 75% of the canvas height. The photo has slightly rounded corners and a thin dark border separating it from the background. LEFT SIDE (35-40% width): 4-5 SMALLER POLAROID-STYLE PHOTOS stacked vertically, each slightly tilted at casual angles (2-6 degrees) with thick white instant-photo borders. Each polaroid shows a COMPLETELY DIFFERENT moment or pose: Polaroid 1 (top): the subject laughing joyfully, candid moment, bright outdoor light. Polaroid 2: a close-up portrait with a playful or thoughtful expression, soft bokeh background. Polaroid 3: the subject in a different outfit, three-quarter body, dynamic pose. Polaroid 4: an artistic shot — the subject from behind or side angle, interesting lighting. Polaroid 5 (bottom, optional): a full-body shot, confident stance, vibrant background. Each polaroid casts a subtle drop shadow on the dark background. BOTTOM-LEFT AREA: {{CALENDAR}} BOTTOM-RIGHT AREA: Elegant calligraphy text reading 'Happy Birthday' in warm white or cream script font with subtle glow. Below that, '{{MESSAGE}}' in a large beautiful decorative calligraphy script — warm gold or cream colour. Small ornamental flourishes or sparkles around the text. COLOUR PALETTE: deep black/charcoal background, warm natural tones in photos, white polaroid borders, cream/gold text. Overall mood: stylish, modern, celebratory dark birthday collage.", Category = "PhotoCollage", IconEmoji = "\U0001F382", AccentColor = "#212121", IsActive = true, SortOrder = 174 },
            new StylePreset { Id = 453, Name = "Birthday Grid Calendar", Description = "Black background photo grid with top calendar and birthday message", PromptTemplate = "DO NOT reproduce the source photo. Generate a BRAND NEW BIRTHDAY GRID CALENDAR COLLAGE on a vertical 2:3 portrait canvas. Use the person from the source photo — preserve their EXACT face, hair, and appearance in every panel. BACKGROUND: Solid BLACK background with tiny scattered golden sparkle/star effects across the entire canvas for a festive look. TOP AREA (25% of canvas): {{CALENDAR}} The calendar should use white text on the dark background with clean modern typography. MIDDLE AREA (50% of canvas): A MOSAIC GRID of 8-10 photographs arranged in a dynamic grid layout with varying sizes — mix of square and rectangular frames. Some photos are larger (feature shots) and some smaller (accent shots). Thin white gaps (2-3px) separate each photo. The grid is asymmetric and visually interesting. Photo variety: Photo 1 (large, top-left): close-up portrait of the subject with a joyful smile, warm lighting. Photo 2 (medium): the subject in a stylish outfit, three-quarter pose, urban or studio background. Photo 3 (small square): candid laughing moment. Photo 4 (medium): the subject outdoors in golden-hour light, dreamy bokeh. Photo 5 (large, centre): the subject in an elegant outfit, full body, confident pose. Photo 6 (small): artistic close-up — profile view or detail shot. Photo 7 (medium): playful pose with props or in a fun setting. Photo 8 (small): a different outfit, lifestyle shot. Each photo has warm vibrant colour grading. CENTRE TEXT AREA (between photo rows): A decorative text block with a warm heartfelt birthday wish — '{{OCCASION}}' in elegant italic script, cream or soft gold colour, 2-3 lines. Small decorative emoji-style elements (hearts, stars, sparkles) scattered around the text. BOTTOM AREA (20% of canvas): Large bold text 'Happy Birthday' in a beautiful display font — warm white or cream with subtle glow effect. Below it: '{{MESSAGE}}' in elegant calligraphy script — soft pink or gold. Small decorative butterflies and floral sprigs on either side of the text — delicate, pastel pink and white. COLOUR PALETTE: black background, golden sparkles, warm photo tones, cream/gold text, soft pink accents. Overall mood: festive, glamorous, modern birthday celebration.", Category = "PhotoCollage", IconEmoji = "\U0001F388", AccentColor = "#FFD54F", IsActive = true, SortOrder = 175 },
            new StylePreset { Id = 454, Name = "Birthday Double Exposure", Description = "Cinematic desaturated double exposure with vivid portrait overlay", PromptTemplate = "DO NOT reproduce the source photo. Generate a BRAND NEW CINEMATIC BIRTHDAY POSTER on a vertical 2:3 portrait canvas. Use the person from the source photo — preserve their EXACT face, hair, and appearance. This should look like a dramatic CINEMATIC POSTER for a birthday celebration. LAYOUT — TOP HALF (55-60% of canvas): A dramatic DOUBLE EXPOSURE / OVERLAY effect. A large, softly DESATURATED close-up of the subject's face and upper body — rendered in muted GREY/SILVER monochrome tones, large scale, filling the upper portion. The image is semi-transparent and dreamlike, blending into the dark background. Show multiple angles or a mirrored/reflected version of the face creating a symmetrical artistic composition. The edges fade and dissolve into soft mist, light particles, or gentle bokeh effects. BOTTOM HALF (40-45% of canvas): A VIVID FULL-COLOUR photograph of the subject — in a smart casual or elegant outfit (blazer, dress, sharp shirt). Standing or posed confidently with warm natural lighting. This photo is crisp, vibrant, and saturated with warm golden-brown tones — dramatically contrasting with the grey overlay above. The subject is shown from approximately waist up. TRANSITION between top and bottom: Smooth gradient dissolve — the grey monochrome top fades gradually into the vivid colour bottom. No hard dividing line. Soft light particles and gentle bokeh orbs (warm gold) float across the transition zone. TEXT ELEMENTS — UPPER-CENTRE (overlaying the double exposure): 'HAPPY BIRTHDAY' in clean uppercase serif or sans-serif font — warm white or soft cream, medium size, elegant spacing. BOTTOM AREA (below or overlaying the colour photo): '{{MESSAGE}}' in large flowing calligraphy script — sage green, warm olive, or soft gold colour. Beautiful decorative flourishes extending from the text. COLOUR PALETTE: grey/silver monochrome (top), warm golden-brown (bottom colour photo), sage green or olive text accents. The contrast between desaturated and vivid is the key visual feature. Overall mood: cinematic, artistic, modern birthday celebration poster.", Category = "PhotoCollage", IconEmoji = "\U0001F3AC", AccentColor = "#78909C", IsActive = true, SortOrder = 176 },

            new StylePreset { Id = 456, Name = "Campus Collage Art", Description = "Mixed-media torn paper collage with college campus life theme", PromptTemplate = "DO NOT simply reproduce the source photo. Generate a BRAND NEW MIXED-MEDIA PAPER COLLAGE ART piece on a vertical 2:3 portrait canvas. Use the subject(s) from the source photo — preserve their EXACT face(s), facial features, hair, skin tone, and appearance. IMPORTANT: Include ONLY the exact number of people from the source image. ART STYLE: The entire image must look like a handmade MIXED-MEDIA COLLAGE — made of torn paper, ripped newspaper clippings, magazine cutouts, watercolour washes, and textured paper fragments all layered together. Every element should have visible torn or cut paper edges with paper fibre texture. Newspaper text columns and book page fragments should be visible beneath and around elements. CENTRE FOCAL POINT (occupying 50-60% of the canvas): The subject(s) rendered as the dominant central figure(s) in this paper collage style. They should be standing confidently, full body or three-quarter, wearing casual college attire — denim jacket, jeans, t-shirt, hoodie, backpack, headphones around neck, carrying books or a coffee cup. Their clothing and body are composed of layered torn paper textures and fabric pattern cutouts — but their FACE must be rendered with high detail preserving exact identity. The figure(s) should feel like they are literally constructed from paper and magazine clippings. BACKGROUND — CAMPUS SCENE: A college campus environment created entirely from torn paper collage elements: TOP AREA: Blue sky made of torn blue and white paper layers. Green paper-cut trees and leaves scattered across the top. University buildings (brick, classical architecture with columns, clock towers) constructed from torn paper — brown, beige, and grey paper textures with visible newspaper text underneath. MIDDLE AREA: A grassy campus quad or walkway behind the central figure(s). Other students walking in the background, rendered as smaller paper collage figures carrying backpacks and books — all in the torn paper art style. BOTTOM AREA: Additional campus life elements as collage fragments — a lecture hall scene with rows of students, scientific diagrams (DNA helix, cell biology, molecular structures), textbook pages, notebook doodles, campus map fragments. These bottom elements should be smaller collage pieces creating a rich layered border. PAPER TEXTURES throughout: Visible torn edges on every element, newspaper text columns peeking through, watercolour paint splashes in green, blue, and warm tones, rough paper grain texture on the off-white/cream background. COLOUR PALETTE: cream/off-white paper base, denim blue, forest green, warm red accents, brown and beige torn paper, black newsprint text. The overall image must look like a physical handmade paper collage artwork — textured, layered, artistic, with visible craft materials.", Category = "PhotoCollage", IconEmoji = "\U0001F3D3", AccentColor = "#1565C0", IsActive = true, SortOrder = 178 },

            new StylePreset { Id = 455, Name = "Number Template", Description = "Giant number filled with photo collage for birthday milestones", PromptTemplate = "DO NOT reproduce the source photo. Generate a BRAND NEW NUMBER PHOTO COLLAGE on a vertical 2:3 portrait canvas. Use the person from the source photo — preserve their EXACT face, hair, and appearance in every photo within the number. BACKGROUND: Clean soft LIGHT GREY or OFF-WHITE background with a very subtle gradient (slightly darker at the edges). Smooth, minimal, studio-style backdrop. CENTRE OF CANVAS: A GIANT number '{{NUMBER}}' rendered as a LARGE 3D NUMERAL that dominates the canvas (approximately 70-80% of canvas height). The number has a subtle 3D depth/thickness effect with soft shadows on the background — as if it's a physical standing object. CRITICAL — PHOTO COLLAGE INSIDE THE NUMBER: The entire surface of the number '{{NUMBER}}' is filled with a MOSAIC of 8-12 different photographs of the subject, arranged as a collage CLIPPED INSIDE the number shape. The photos should be tightly packed with thin white gaps (1-2px) between them, all contained within the outline of the digit(s). Photo variety inside the number: mix of close-up portraits (joyful smiles, laughing), three-quarter body shots (different outfits, playful poses), candid moments (playing, exploring, celebrating), and lifestyle shots. Each photo has warm natural lighting and vibrant colours. The photos are cropped to different rectangular sizes to fill the number shape completely — no empty space inside the digit. Outside the number outline, the background remains clean and minimal. TOP AREA (above the number): Elegant text '{{MESSAGE}}' in a beautiful flowing handwritten calligraphy script — dark charcoal or warm brown colour. This should be a personalized name or heading like 'Melissa Turned Two' or 'Aarav is 5'. BOTTOM AREA (below the number): Text 'Happy Birthday' in elegant decorative script — dark charcoal or warm gold. Below that, the date '{{DATE}}' in a clean refined sans-serif or serif font — slightly smaller, warm grey or gold colour. IMPORTANT: Do NOT repeat 'Happy Birthday' anywhere else in the image — it should appear ONLY ONCE in the bottom area. OVERALL STYLE: The final image should look like a professional birthday milestone poster — clean white/grey background with a stunning photo-filled number as the centrepiece. Soft drop shadow behind the number for depth. COLOUR PALETTE: light grey/white background, warm vibrant photos inside the number, dark charcoal or gold text.", Category = "PhotoCollage", IconEmoji = "\U0001F522", AccentColor = "#9E9E9E", IsActive = true, SortOrder = 177 },

            // ── Trending ──
            new StylePreset { Id = 457, Name = "Traditional Makeup Portrait", Description = "Intimate close-up of traditional makeup and adornment being applied", PromptTemplate = "DO NOT reproduce the source photo. Generate a BRAND NEW TRADITIONAL MAKEUP PORTRAIT on a vertical 2:3 portrait canvas. Use the person from the source photo — preserve their EXACT face, facial bone structure, skin tone, eye shape, nose shape, lip shape, hair texture, and every facial detail with photorealistic accuracy. The person's gender, age, and ethnicity must remain exactly as in the source photo. SCENE: An intimate, candid close-up moment of the subject getting traditional ceremonial makeup applied. The subject is adorned in rich traditional Indian jewellery appropriate to their gender and age — ornate headpiece (maang tikka or forehead jewellery), delicate nose ring with chain (nath), layered gold necklaces, and fresh orange marigold garlands and white jasmine flowers woven into the hair. The subject's eyes are the focal point — large, expressive, beautifully lined with black kohl/kajal. Show a hand (from another person, partially out of frame with blurred foreground) carefully applying kajal or eyeliner to the subject's eye with a thin applicator brush. The subject gazes slightly upward with a serene, focused expression. LIGHTING: Warm golden ambient light — soft and intimate like candlelight or warm indoor lighting. Rich warm tones with deep shadows creating a moody, cinematic atmosphere. Shallow depth of field — the subject's face and eye area are tack-sharp while foreground elements (the hand applying makeup, flower garlands) are softly blurred creating beautiful bokeh. COLOUR PALETTE: warm golds, deep oranges from marigold flowers, rich royal blue from traditional silk fabric visible at the shoulder/drape area, deep blacks in the background, warm skin tones with golden highlights. The overall mood is intimate, sacred, ceremonial — like a precious moment of preparation before a traditional celebration. IMPORTANT: This must work for any person regardless of age or gender — adapt the jewellery and adornment style appropriately (e.g., simpler jewellery for children, masculine traditional ornaments for men). The face and all facial features MUST be an exact match to the source photo.", Category = "Trending", IconEmoji = "\U0001F48D", AccentColor = "#FF8F00", IsActive = true, SortOrder = 179 },
            new StylePreset { Id = 459, Name = "Event Filmmaker", Description = "Professional cinematographer at a live event with cinema camera and headphones", PromptTemplate = "DO NOT reproduce the source photo. Generate a BRAND NEW FILMMAKER PORTRAIT on a vertical 2:3 portrait canvas. Use the person from the source photo — preserve their EXACT face, facial bone structure, skin tone, eye shape, nose shape, lip shape, jaw shape, facial hair (if any), hair texture, hair colour, hair length, and every facial detail with photorealistic accuracy. The person's gender, age, and ethnicity must remain exactly as in the source photo. SCENE: The subject is a professional cinematographer/filmmaker at a large indoor event or conference. They are standing confidently, smiling warmly at the camera while holding a professional cinema camera rig. EQUIPMENT: The subject holds a full cinema camera setup — a professional RED or ARRI-style digital cinema camera body mounted on a handheld gimbal stabiliser (like a DJI Ronin or Freefly MoVI). The camera has a large cinema lens, a compact on-camera monitor mounted on top, and a shotgun microphone attached to the top handle. The subject wears professional over-ear monitoring headphones around their head. They grip the gimbal handle with both hands in a natural working position. CLOTHING: Casual professional — a dark grey or charcoal hoodie/pullover, comfortable and practical filmmaker attire. BACKGROUND: A large indoor event venue or conference hall — rows of chairs visible behind, a stage with colourful LED stage lights creating beautiful blue and purple bokeh in the background. Warm amber and cool blue lighting mix. The background is heavily blurred (shallow depth of field, f/1.4-2.0) creating rich circular bokeh from the stage lights. LIGHTING: Mixed warm and cool event lighting — warm key light on the subject's face from the front, cool blue ambient fill from the stage lights behind. The subject's face is well-lit and the expression is friendly, approachable, and confident. COLOUR PALETTE: warm skin tones, charcoal grey clothing, blue and purple bokeh highlights, warm amber accents. Overall mood: professional, energetic, behind-the-scenes at a major event. IMPORTANT: This must work for any person regardless of age or gender. The face and ALL facial features MUST be an exact match to the source photo — do not alter facial structure, skin tone, or any identifying features.", Category = "Trending", IconEmoji = "\U0001F3AC", AccentColor = "#5C6BC0", IsActive = true, SortOrder = 181 },
            new StylePreset { Id = 460, Name = "Outdoor Filmmaker", Description = "Cinematic filmmaker shooting on location with professional camera on tripod", PromptTemplate = "DO NOT reproduce the source photo. Generate a BRAND NEW OUTDOOR FILMMAKER PORTRAIT on a vertical 2:3 portrait canvas. Use the person from the source photo — preserve their EXACT face, facial bone structure, skin tone, eye shape, nose shape, lip shape, jaw shape, facial hair (if any), hair texture, hair colour, hair length, and every facial detail with photorealistic accuracy. The person's gender, age, and ethnicity must remain exactly as in the source photo. SCENE: The subject is a professional cinematographer/filmmaker shooting on an outdoor film location. They are shown in a focused side-profile or three-quarter view, concentrating intently on their work, operating the camera. EQUIPMENT: The subject is operating a professional cinema camera (RED Komodo, Canon C70, or Sony FX6 style) mounted on a professional tripod with a fluid head. The camera has a large cinema zoom lens, a compact field monitor mounted on top showing the shot being filmed, and professional accessories (follow focus, matte box or lens hood). The subject's hands are on the camera controls, adjusting settings or framing the shot. CLOTHING: Practical outdoor filmmaker attire — a dark olive green, charcoal, or navy windbreaker/field jacket, layered for outdoor shooting. Hair slightly tousled by the wind, natural and candid. BACKGROUND: An outdoor rural or semi-urban location — bare trees, an old house or rustic structure slightly visible, soft overcast sky. The background is beautifully blurred with shallow depth of field (f/2.0-2.8), creating a soft dreamy bokeh with muted earthy tones. Slight haze or atmospheric mist adding depth and cinematic quality. LIGHTING: Soft diffused natural daylight — overcast sky providing even, flattering light on the subject. Subtle rim light on the hair and shoulders from behind. Cool desaturated colour grading with slight teal shadows and warm skin tone highlights — a cinematic colour grade. COLOUR PALETTE: muted earthy tones — olive green, charcoal, soft browns, desaturated greens from foliage, cool grey sky, warm natural skin tones. Overall mood: focused, artistic, behind-the-scenes on a film set, cinematic and atmospheric. IMPORTANT: This must work for any person regardless of age or gender. The face and ALL facial features MUST be an exact match to the source photo — do not alter facial structure, skin tone, or any identifying features.", Category = "Trending", IconEmoji = "\U0001F3AC", AccentColor = "#455A64", IsActive = true, SortOrder = 182 },

            new StylePreset { Id = 461, Name = "Race Car Driver", Description = "Cinematic close-up of a race car driver in helmet inside a cockpit", PromptTemplate = "DO NOT reproduce the source photo. Generate a BRAND NEW RACE CAR DRIVER PORTRAIT on a vertical 2:3 portrait canvas. Use the person from the source photo — preserve their EXACT face, facial bone structure, skin tone, eye shape, nose shape, lip shape, jaw shape, facial hair (if any), hair texture, hair colour, hair length, and every facial detail with photorealistic accuracy. The person's gender, age, and ethnicity must remain exactly as in the source photo. SCENE: A dramatic cinematic close-up of the subject as a professional race car driver, seated inside the cockpit of a high-performance racing car. HELMET: The subject wears a sleek glossy BLACK full-face racing helmet with the tinted visor FLIPPED UP, fully revealing their face. The helmet has subtle metallic gold or silver accent stripes and a reflective visor surface. The helmet fits snugly and looks authentic — professional motorsport grade. The subject's face is clearly visible through the open visor — eyes looking ahead with intense focus and determination, or gazing slightly to one side with quiet confidence. COCKPIT: The interior of a racing car is visible — a roll cage with metal tubular bars behind and to the side, a racing bucket seat with harness straps over the shoulders, carbon fibre dashboard elements. The cockpit feels tight and authentic. CLOTHING: The subject wears a professional black racing suit (fireproof Nomex) with subtle sponsor logos or racing team patches. A HANS device or neck restraint may be partially visible. LIGHTING: Dramatic golden-hour sunlight streaming in from the side/front of the cockpit — warm amber light illuminating one side of the subject's face while the other side falls into soft shadow. Beautiful contrast between warm highlights and cool cockpit shadows. Slight lens flare from the sunlight adds cinematic quality. COLOUR PALETTE: deep blacks from the helmet and suit, warm golden amber from sunlight, metallic silver from the helmet visor, muted dark tones of the cockpit interior. Overall mood: intense, focused, powerful, cinematic motorsport photography. IMPORTANT: This must work for any person regardless of age or gender — the helmet, suit, and cockpit remain the same, only the face changes to match the source photo exactly. The face and ALL facial features MUST be an exact match to the source photo — do not alter facial structure, skin tone, or any identifying features.", Category = "Trending", IconEmoji = "\U0001F3CE\uFE0F", AccentColor = "#212121", IsActive = true, SortOrder = 183 },
            new StylePreset { Id = 462, Name = "Neon Superbike Rider", Description = "Full neon cyberpunk scene with glowing superbike and futuristic rider", PromptTemplate = "DO NOT reproduce the source photo. Generate a BRAND NEW FULL NEON CYBERPUNK SUPERBIKE SCENE on a vertical 2:3 portrait canvas. Use the person from the source photo — preserve their EXACT face, facial bone structure, skin tone, eye shape, nose shape, lip shape, jaw shape, facial hair (if any), hair texture, hair colour, hair length, and every facial detail with photorealistic accuracy. The person's gender, age, and ethnicity must remain exactly as in the source photo. ENTIRE IMAGE STYLE: The WHOLE image must be bathed in vivid neon colours — everything glows with neon light. This is a full cyberpunk neon aesthetic where every element radiates colour. SCENE: The subject is sitting astride a futuristic high-performance superbike in a dramatic posed shot. The motorcycle is parked or stationary, and the subject is seated on it in a confident, powerful stance — one hand on the handlebar, other hand resting on their thigh or removing their helmet. The subject's face is FULLY VISIBLE (helmet off, held under one arm or resting on the tank, or no helmet at all). MOTORCYCLE: A sleek, aggressive futuristic superbike with an aerodynamic black gloss body — sharp angular fairings, sculpted curves, and muscular proportions. The ENTIRE bike glows with vivid NEON PINK/MAGENTA and NEON CYAN/BLUE LED accent lights — glowing strips running along every fairing edge, wheel rims fully illuminated with neon pink light rings, engine area with intense magenta underglow, thin neon lines tracing every contour of the bodywork, brake calipers glowing, exhaust with neon accents. The wheels cast neon reflections on the ground. CLOTHING: The subject wears a sleek black leather motorcycle jacket with NEON PINK piping, glowing neon accents on the zippers and seams, neon-trimmed riding gloves, black riding pants with neon side-stripe accents, and boots with subtle glow. The outfit has a futuristic cyberpunk aesthetic with visible neon elements. BACKGROUND: A NEON-DRENCHED cyberpunk cityscape at night — dark buildings with vivid neon signs in pink, magenta, cyan, and electric blue. Neon light strips on building edges, glowing holographic advertisements, neon-lit storefronts. The entire environment pulses with colour. The floor/street is wet and reflective, creating stunning mirror reflections of all the neon lights — pink and blue streaks reflected across the wet ground. Atmospheric neon-tinted fog/mist fills the scene, catching light and creating volumetric neon rays. LIGHTING: The entire scene is lit by neon sources — vivid neon pink/magenta is the dominant colour, with neon cyan/blue as the secondary accent. Every surface catches and reflects neon light. The subject's face is illuminated by the neon glow — pink light on one side, cyan on the other, creating a striking split-tone effect while keeping facial details clearly visible. Neon light reflects off the subject's skin, hair, and clothing. COLOUR PALETTE: deep black base, vivid neon pink/magenta (dominant), electric cyan/blue (accent), neon purple where pink and blue mix, hot neon reflections on every wet/glossy surface. NO dull or neutral areas — the entire image should feel like it's glowing with neon energy. Overall mood: futuristic, electrifying, cyberpunk, visually stunning, every pixel alive with neon colour. IMPORTANT: This must work for any person regardless of age or gender. The subject MUST be sitting on the bike with their face clearly visible and matching the source photo exactly. The face and ALL facial features MUST be an exact match to the source photo — do not alter facial structure, skin tone, or any identifying features.", Category = "Trending", IconEmoji = "\U0001F3CD\uFE0F", AccentColor = "#E91E63", IsActive = true, SortOrder = 184 },

            new StylePreset { Id = 463, Name = "Epic Warrior King", Description = "Baahubali-style epic warrior movie poster collage with name overlay", PromptTemplate = "DO NOT reproduce the source photo. Generate a BRAND NEW EPIC WARRIOR KING MOVIE POSTER COLLAGE on a vertical 2:3 portrait canvas. Use the person from the source photo — preserve their EXACT face, facial bone structure, skin tone, eye shape, nose shape, lip shape, jaw shape, facial hair (if any), hair texture, hair colour, and every facial detail with photorealistic accuracy. The person's gender, age, and ethnicity must remain exactly as in the source photo. OVERALL STYLE: A dramatic multi-layered cinematic movie poster — like a Baahubali or ancient Indian warrior epic film poster. Multiple images of the same subject layered together in a rich, warm golden composite. LAYOUT — TOP AREA (upper 25-30%): A massive DOUBLE EXPOSURE of the subject's EYES AND UPPER FACE — just the intense, piercing eyes, eyebrows, and bridge of the nose, rendered in a warm desaturated sepia/golden tone, filling the entire width of the canvas. The expression is fierce, determined, and commanding. The eyes fade and dissolve downward into the layers below with a smoky, misty transition. BOLD TEXT across the top area or just below the eyes: 'THE REIGN OF' in elegant wide-spaced uppercase serif font, warm gold metallic colour. Below that in MASSIVE bold letters: '{{MESSAGE}}' — the user's name rendered in grand, ornate gold metallic text with subtle embossing, glow, and decorative flourishes. The text should feel royal and epic, like a movie title. MIDDLE AREA (centre 40-45%): The PRIMARY HERO SHOT — the subject as a powerful ancient Indian warrior king in a dynamic action pose. They wear ornate ancient warrior battle armour — a detailed breastplate with a large circular golden sun/bull emblem medallion on the chest, layered leather and metal shoulder guards, arm bracers with gold filigree, and a magnificent ornate CROWN or royal headpiece (like the iconic Mahishmati crown — an elaborate golden metallic crown with intricate carvings). The subject has long flowing wild hair (or their natural hair enhanced dramatically), and holds a gleaming golden SWORD raised high in a battle cry pose — arm extended upward, mouth open in a fierce war cry, muscles tensed. Behind this hero shot: a burning ancient city or fortress — massive stone architecture engulfed in orange flames and thick smoke, creating a dramatic fiery battlefield backdrop. Sparks and embers float in the air. LOWER-LEFT AREA: A second image of the subject — a CLOSE-UP three-quarter PORTRAIT as the warrior king, calm and regal. Wearing the same ornate armour and crown, looking slightly to the side with a confident, noble expression. Warm golden lighting highlights their face. This image overlaps slightly with the hero shot above. LOWER-RIGHT AND BOTTOM AREA: Additional layered elements — soldiers or warriors in silhouette charging into battle, ancient war elephants, flaming arrows arcing through the sky, a grand ancient Indian palace/fortress (Mahishmati-style) with towering walls and ornate architecture visible through the smoke. These background elements are rendered in warm golden-sepia tones, partially transparent, creating depth and scale. BOTTOM EDGE: Subtle decorative border with ancient Indian motifs — lotus patterns, sun symbols, or Sanskrit-inspired ornamental designs in gold. COLOUR PALETTE: Rich warm golden throughout — amber, burnt orange, deep gold, warm sepia brown, fiery orange-red from flames, dark charcoal shadows. The entire poster has a unified warm golden colour grading like a bronze/gold-toned cinematic poster. No cool colours. LIGHTING: Dramatic epic cinematic lighting — strong warm backlight creating rim-light on the hero, fire providing orange illumination, atmospheric haze and smoke catching golden light. IMPORTANT: This must work for any person regardless of age or gender — adapt the warrior attire appropriately (warrior queen armour for women, age-appropriate styling for younger subjects, but always epic and powerful). The face and ALL facial features MUST be an exact match to the source photo.", Category = "Trending", IconEmoji = "\U0001F451", AccentColor = "#FF8F00", IsActive = true, SortOrder = 185 },

            new StylePreset { Id = 464, Name = "Wildlife Photographer", Description = "Multi-panel wildlife photography collage with name in stylish lettering", PromptTemplate = "DO NOT reproduce the source photo. Generate a BRAND NEW WILDLIFE PHOTOGRAPHER COLLAGE on a vertical 2:3 portrait canvas. Use the person from the source photo — preserve their EXACT face, facial bone structure, skin tone, eye shape, nose shape, lip shape, jaw shape, facial hair (if any), hair texture, hair colour, hair length, and every facial detail with photorealistic accuracy. The person's gender, age, and ethnicity must remain exactly as in the source photo. LAYOUT: The canvas is divided into 4 horizontal panels stacked vertically, separated by thin white gaps (3px). Each panel is a different cinematic wildlife scene. NAME OVERLAY: The text '{{MESSAGE}}' must be displayed in LARGE stylish modern sans-serif or adventure-style lettering — bold, wide-spaced uppercase with a subtle emboss or 3D shadow effect. The text should be warm white or cream with a soft drop shadow, overlaid across the centre of the canvas spanning over the middle two panels. The letters should feel adventurous and premium — like a National Geographic photographer's personal brand logo. A thin elegant tagline below the name reading 'WILDLIFE PHOTOGRAPHER' in smaller wide-spaced uppercase letters. PANEL 1 (top, ~25% height): A breathtaking wide-angle wildlife scene — two or three majestic African elephants walking through tall golden savanna grass at golden hour. Warm amber sunlight, dust particles floating in the air, dramatic sky with warm clouds. Shot from behind/side showing the elephants' massive silhouettes. Lush green and golden tones. Cinematic and epic. PANEL 2 (upper-middle, ~30% height — the largest panel): The subject as a professional wildlife photographer in ACTION. They are crouching low in tall green grass or bush, eye pressed against the viewfinder of a massive professional camera with a huge WHITE telephoto lens (like a Canon 600mm f/4 or similar super-telephoto). They wear practical safari/outdoor clothing — an olive green or khaki field vest with multiple pockets, dark cargo pants, and a wide-brimmed safari hat or cap. Their posture is focused and stealthy — elbows braced, perfectly still, capturing the shot. The background shows soft-focus African savanna — green trees, open grassland. Natural warm lighting. This is the hero panel and should be the most detailed. PANEL 3 (lower-middle, ~20% height): A stunning close-up wildlife portrait — a majestic giraffe's head and long neck in profile, with beautiful spotted pattern, gentle eyes, and soft bokeh of green acacia trees behind. Warm natural savanna lighting. The giraffe appears calm and noble — as if the subject just photographed this magnificent creature. Rich warm brown, golden, and green tones. PANEL 4 (bottom, ~25% height): The subject standing in an open African landscape — full body or three-quarter shot, wearing the same safari outfit, holding the camera with big telephoto lens in one hand at their side, other hand raised pointing into the distance at something exciting (a herd, a bird, a distant animal). They look adventurous and passionate. Behind them: a wide open African savanna vista with scattered acacia trees, distant mountains or hills, warm golden-hour sky. The mood is adventurous and free. COLOUR PALETTE: Rich warm natural tones throughout — golden savanna yellow, deep olive green, warm amber sunlight, earthy khaki brown, soft sky blue. Each panel has warm natural-light photography aesthetic. Unified warm colour grading across all panels. Overall mood: adventurous, professional, National Geographic quality, celebrating wildlife and nature photography. IMPORTANT: This must work for any person regardless of age or gender. The face and ALL facial features MUST be an exact match to the source photo.", Category = "Trending", IconEmoji = "\U0001F4F7", AccentColor = "#558B2F", IsActive = true, SortOrder = 186 },

            new StylePreset { Id = 458, Name = "Classical Dance Portrait", Description = "Full-body classical Indian dance pose with traditional costume and mudra", PromptTemplate = "DO NOT reproduce the source photo. Generate a BRAND NEW CLASSICAL DANCE PORTRAIT on a vertical 2:3 portrait canvas. Use the person from the source photo — preserve their EXACT face, facial bone structure, skin tone, eye shape, nose shape, lip shape, hair texture, and every facial detail with photorealistic accuracy. The person's gender, age, and ethnicity must remain exactly as in the source photo. SCENE: The subject is posed in a classical Indian dance stance (Bharatanatyam aramandi — a graceful half-seated position with knees bent outward). Both hands are held in expressive dance mudras (hand gestures) — fingers precisely positioned in Alapadma or Katakamukha mudra with elegant wrist angles. COSTUME: The subject wears a traditional classical dance costume — a rich red and gold Kanchipuram silk outfit with intricate gold zari border work. The costume includes a beautifully pleated fan-shaped fabric arrangement at the front (created from the saree pleats fanning out between the legs). A decorative gold waist belt (oddiyanam/ottiyanam) with ornate medallion designs. Gold armlets (vanki) on the upper arms, multiple gold bangles on both wrists, and ankle bells (ghungroo). JEWELLERY AND HAIR: Traditional temple jewellery — a layered gold necklace set with a choker and a longer chain with pendant, gold jhumka earrings, a decorative headpiece (surya/chandra on either side of the hair parting), and a tikka on the forehead. Hair styled in a classical dance bun adorned with a ring of fresh white jasmine flowers (gajra) and a decorative hair ornament. Traditional makeup with bold eyes — thick kajal, dramatic eye makeup, red bindi, and red alta/kumkum on the fingertips and feet soles. BACKGROUND: Deep dark teal-to-navy blue studio backdrop — smooth gradient, slightly lighter in the centre behind the subject creating a soft spotlight effect. Clean and elegant with no distracting elements. LIGHTING: Professional studio lighting — warm golden key light from the front-left illuminating the subject beautifully, with soft fill light to prevent harsh shadows. The gold jewellery and silk costume should shimmer and catch the light. COLOUR PALETTE: rich red and gold costume, warm golden skin tones, deep teal-navy background, white jasmine flowers, gleaming gold jewellery. IMPORTANT: This must work for any person regardless of age or gender — adapt the costume appropriately (e.g., dhoti-style for male dancers, simpler costume for children, age-appropriate styling). The face and all facial features MUST be an exact match to the source photo.", Category = "Trending", IconEmoji = "\U0001F483", AccentColor = "#C62828", IsActive = true, SortOrder = 180 },

            new StylePreset { Id = 451, Name = "Motherhood Collage", Description = "Warm sepia-toned collage with rounded frames and motherhood text", PromptTemplate = "DO NOT reproduce the source photo. Generate a BRAND NEW MOTHERHOOD CELEBRATION COLLAGE on a vertical 2:3 portrait canvas. Use the subject(s) from the source photo — preserve their EXACT face(s), hair, and appearance in every panel. IMPORTANT: Include ONLY the exact number of people from the source image. If the source has 1 person, show only that person throughout in different maternity poses. If the source has 2 people, show them together. BACKGROUND: A large FADED desaturated photograph of the subject fills the entire canvas as a background watermark — rendered in very soft sepia/olive tones at ~20-25% opacity, creating a subtle textured backdrop. The subject in this background is shown in a gentle maternal pose (cradling belly, looking down softly, or standing in profile). COLOUR OVERLAY on the background: warm olive-green and soft sepia gradient wash, muted and dreamy. PHOTO FRAMES: THREE ROUNDED-RECTANGLE PHOTO FRAMES arranged in a pleasing composition on the canvas — one large (top-right area, ~35% canvas width), one medium (left-centre area, ~30%), one medium (bottom-right area, ~28%). Each frame has THICK ROUNDED CORNERS (border-radius ~15-20px) and a subtle warm cream/gold border (3-4px). Frame 1 (top-right, largest): the subject(s) in elegant white/cream outfits during a maternity photoshoot — outdoors at golden hour, warm sunset light, showing the baby bump. Soft warm golden tones. Frame 2 (left-centre): a tender close-up — the subject looking down at the baby bump with hands gently cradling, soft natural light, intimate emotional moment. Warm sepia-touched colour grading. Frame 3 (bottom-right): the subject(s) in another setting — perhaps silhouetted against a sunset, or in a garden/beach, playful or joyful moment, different outfit from other frames. Warm amber tones. TEXT ELEMENTS — CENTRE-LEFT AREA: An elegant quote in refined serif italic font: '{{OCCASION}}' — rendered in warm dark olive or charcoal, 2-3 lines of poetic text. BOTTOM-CENTRE: Large bold artistic text '{{MESSAGE}}' in an elegant display font — warm olive-green or deep gold colour, commanding presence. A thin decorative botanical vine or leaf element above or below the text. COLOUR PALETTE: warm olive-green, soft sepia, cream, golden amber, muted warm tones throughout. Unified warm vintage colour grading. Overall mood: warm, tender, celebratory, maternal elegance.", Category = "PhotoCollage", IconEmoji = "\U0001F932", AccentColor = "#827717", IsActive = true, SortOrder = 173 }
        );
